def caesar_cipher(text: str, shift: int) -> str:
    result = []
    for char in text:
        if 'a <= char <= 'z':
            shifted = chr((ord(char) - ord('a') + shift) % 26 + ord('a'))
            result.append(shifted)
        elif 'A <= char <= 'Z':
            shifted = chr((ord(char) - ord('A') + shift) % 26 + ord('A'))
            result.append(shifted)
        else:
            result.append(char)
    return ''.join(result)
