import re

def word_frequency(text: str) -> dict[str, int]:
    if not text:
        return {}

    # Split on whitespace and strip punctuation from word edges
    words = re.split(r'\s+', text.strip())
    cleaned_words = []

    for word in words:
        # Remove punctuation from the beginning and end of each word
        cleaned_word = re.sub(r'^[^\w]+|[^\w]$', '', word)
        if cleaned_word:
            cleaned_words.append(cleaned_word.lower())

    # Count frequency of each word
    frequency = {}
    for word in cleaned_words:
        frequency[word] = frequency.get(word, 0) + 1

    return frequency
```

